mapper.select:
select 
from courses c
where c.id = #{id}

mapper.update:
update courses
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and owner_member_id = #{ownerMemberId}
  and deleted_at is null

mapper.select:
select 
from courses c
where c.region_name = #{regionName}
  and c.deleted_at is null
order by (
    select count(*) from course_saves s where s.course_id = c.id
) desc, c.created_at desc, c.id asc
limit #{limit}

mapper.delete:
delete from course_saves
where course_id = #{courseId}
  and member_id = #{memberId}
